export function getVariant(id, format, size) {
  const p = CATALOG[id];
  if (!p) return null;
  return p.variants.find(v => v.format === format && v.size === size) || null;
}

// Public catalog for the browser (no secrets to hide, but keep it lean).
export function publicCatalog() {
  const out = {};
  for (const [id, p] of Object.entries(CATALOG)) {
    out[id] = { id, title: p.title, image: p.image,
      variants: p.variants.map(v => ({ format: v.format, size: v.size, cents: v.cents, label: v.label })) };
  }
  return out;
}
